import { Routes } from '@angular/router';
import { AuthGuard } from './core/guards/auth.guard';

export const routes: Routes = [
  {
    path: 'auth',
    // Cambiamos a la ruta exacta desde src/app/
    loadComponent: () => import('./features/auth/login/login.component').then(m => m.LoginComponent)
  },
  {
    path: 'proyectos',
    canActivate: [AuthGuard],
    loadComponent: () => import('./features/proyectos/proyectos-list/proyectos-list.component').then(m => m.ProyectosListComponent)
  },
  {
    path: '',
    redirectTo: 'auth',
    pathMatch: 'full'
  },
  {
    path: '**',
    redirectTo: 'auth'
  }
];
